// Extract SKUs from request
const body = $input.first().json.body;
const skus = body.skus || [];

if (!Array.isArray(skus) || skus.length === 0) {
  throw new Error('No SKUs provided in request');
}

// Create individual items for each SKU
return skus.map(sku => ({
  json: {
    sku: sku,
    lookup_timestamp: new Date().toISOString()
  }
}));

// Extract relevant product data for fulfillment
const product = $input.first().json;
const requestedSku = $node['Extract SKUs'].json.sku;

// Parse JSON fields
let imageUrls = [];
let videoUrls = [];

try {
  if (product.image_urls) {
    imageUrls = typeof product.image_urls === 'string' 
      ? JSON.parse(product.image_urls) 
      : product.image_urls;
  }
} catch (e) {
  console.error('Failed to parse image_urls:', e);
}

try {
  if (product.video_urls) {
    videoUrls = typeof product.video_urls === 'string' 
      ? JSON.parse(product.video_urls) 
      : product.video_urls;
  }
} catch (e) {
  console.error('Failed to parse video_urls:', e);
}

return [{
  json: {
    sku: product.SKU || requestedSku,
    name: product.Name,
    description: product.Copy_html,
    tagline: product.Tagline,
    image_urls: imageUrls,
    video_urls: videoUrls,
    vendor_id: product.vendor_id,
    source_tier: product.source_tier,
    found_in_cache: true,
    cache_hit: true,
    lookup_timestamp: new Date().toISOString()
  }
}];

// Mark SKU as missing (cache miss)
const requestedSku = $node['Extract SKUs'].json.sku;

return [{
  json: {
    sku: requestedSku,
    name: null,
    description: null,
    tagline: null,
    image_urls: [],
    video_urls: [],
    vendor_id: null,
    source_tier: null,
    found_in_cache: false,
    cache_hit: false,
    needs_scraping: true,
    lookup_timestamp: new Date().toISOString()
  }
}];

// Aggregate lookup results
const allResults = $input.all();

const foundProducts = allResults.filter(r => r.json.cache_hit);
const missingSkus = allResults.filter(r => !r.json.cache_hit);

const cacheHitRate = allResults.length > 0 
  ? (foundProducts.length / allResults.length) 
  : 0;

return [{
  json: {
    found_products: foundProducts.map(p => p.json),
    missing_skus: missingSkus.map(m => m.json.sku),
    total_skus: allResults.length,
    cache_hits: foundProducts.length,
    cache_misses: missingSkus.length,
    cache_hit_rate: cacheHitRate,
    cache_hit_percentage: (cacheHitRate * 100).toFixed(2) + '%',
    timestamp: new Date().toISOString()
  }
}];

// Log cache performance metrics
const results = $input.first().json;

console.log('=== SKU Lookup Performance ===');
console.log(`Total SKUs: ${results.total_skus}`);
console.log(`Cache Hits: ${results.cache_hits}`);
console.log(`Cache Misses: ${results.cache_misses}`);
console.log(`Cache Hit Rate: ${results.cache_hit_percentage}`);

if (results.cache_hit_rate < 0.9) {
  console.warn('⚠️ Cache hit rate below 90% target!');
}

if (results.missing_skus.length > 0) {
  console.log('Missing SKUs:', results.missing_skus.join(', '));
}

return [$input.first()];
